export function getDocumentById(id: string): Document | undefined {
  return mockDocuments.find(doc => doc.id === id);
}

export function getBreadcrumbPath(folders: Folder[], folderId: string): { id: string; name: string }[] {
  const path: { id: string; name: string }[] = [];

  function findPath(items: Folder[], targetId: string): boolean {
    for (const folder of items) {
      if (folder.id === targetId) {
        path.push({ id: folder.id, name: folder.name });
        return true;
      }
      if (folder.children && findPath(folder.children, targetId)) {
        path.unshift({ id: folder.id, name: folder.name });
        return true;
      }
    }
    return false;
  }

  findPath(folders, folderId);
  return path;
}
